#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding gastroenterology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    full_name:string! \
    date_of_birth:date \
    nhs_number:string! \
    address:text! \
    telephone:string! \
    email:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    chief_complaint:text! \
    onset_date:date \
    duration:string! \
    symptom_pattern:string! \
    severity:string! \
    impact_on_daily_life:string! \
    previous_investigations:text! \
    previous_treatment:text! \
    previous_treatment_response:string! \
    --htmx

cargo loco generate scaffold assessment_upper_gi_symptoms \
    assessment:references \
    dysphagia:string! \
    dysphagia_type:string! \
    dysphagia_progression:string! \
    odynophagia:string! \
    heartburn:string! \
    heartburn_frequency:string! \
    acid_regurgitation:string! \
    nausea:string! \
    nausea_frequency:string! \
    vomiting:string! \
    vomiting_frequency:string! \
    haematemesis:string! \
    early_satiety:string! \
    bloating:string! \
    epigastric_pain:string! \
    epigastric_pain_relation_to_meals:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_lower_gi_symptoms \
    assessment:references \
    altered_bowel_habit:string! \
    bowel_habit_change_type:string! \
    stool_frequency_per_day:int \
    bristol_stool_type:int \
    rectal_bleeding:string! \
    bleeding_colour:string! \
    melaena:string! \
    mucus_in_stool:string! \
    tenesmus:string! \
    urgency:string! \
    incontinence:string! \
    flatulence:string! \
    abdominal_distension:string! \
    perianal_symptoms:string! \
    perianal_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_abdominal_pain \
    assessment:references \
    has_abdominal_pain:string! \
    pain_location:string! \
    pain_character:string! \
    pain_severity:int \
    pain_radiation:text! \
    pain_onset:string! \
    pain_duration:string! \
    pain_aggravating_factors:text! \
    pain_relieving_factors:text! \
    relation_to_meals:string! \
    relation_to_defecation:string! \
    nocturnal_pain:string! \
    associated_weight_loss:string! \
    weight_loss_amount_kg:double \
    weight_loss_duration:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_liver_and_pancreas \
    assessment:references \
    jaundice:string! \
    jaundice_duration:string! \
    dark_urine:string! \
    pale_stools:string! \
    pruritus:string! \
    hepatomegaly:string! \
    ascites:string! \
    history_of_hepatitis:string! \
    hepatitis_type:string! \
    history_of_liver_disease:string! \
    liver_disease_details:text! \
    alcohol_consumption:string! \
    alcohol_units_per_week:int \
    history_of_pancreatitis:string! \
    pancreatitis_type:string! \
    history_of_gallstones:string! \
    cholecystectomy_performed:string! \
    liver_function_tests_available:string! \
    lft_notes:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_previous_gi_history \
    assessment:references \
    has_ibs:string! \
    ibs_subtype:string! \
    has_ibd:string! \
    ibd_type:string! \
    has_coeliac_disease:string! \
    has_peptic_ulcer:string! \
    helicobacter_pylori_status:string! \
    has_gord:string! \
    has_barretts_oesophagus:string! \
    has_gi_malignancy:string! \
    gi_malignancy_details:text! \
    has_polyps:string! \
    polyp_details:text! \
    previous_endoscopy:string! \
    endoscopy_date:date \
    endoscopy_findings:text! \
    previous_colonoscopy:string! \
    colonoscopy_date:date \
    colonoscopy_findings:text! \
    previous_gi_surgery:string! \
    gi_surgery_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_ppi:string! \
    ppi_name:string! \
    takes_h2_blocker:string! \
    h2_blocker_name:string! \
    takes_antacids:string! \
    takes_laxatives:string! \
    laxative_type:string! \
    takes_antidiarrhoeals:string! \
    takes_nsaids:string! \
    nsaid_name:string! \
    takes_anticoagulants:string! \
    anticoagulant_name:string! \
    takes_immunosuppressants:string! \
    immunosuppressant_name:string! \
    takes_biologics:string! \
    biologic_name:string! \
    takes_antibiotics:string! \
    antibiotic_name:string! \
    takes_probiotics:string! \
    other_medications:text! \
    --htmx

cargo loco generate scaffold assessment_allergies_and_diet \
    assessment:references \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    has_food_allergies:string! \
    food_allergy_details:text! \
    has_food_intolerances:string! \
    food_intolerance_details:text! \
    lactose_intolerance:string! \
    gluten_sensitivity:string! \
    fructose_intolerance:string! \
    dietary_restrictions:text! \
    diet_type:string! \
    diet_type_other:text! \
    fibre_intake:string! \
    fluid_intake_litres:double \
    caffeine_intake:string! \
    nutritional_supplements:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_red_flags_and_social \
    assessment:references \
    unintentional_weight_loss:string! \
    progressive_dysphagia:string! \
    gi_bleeding:string! \
    iron_deficiency_anaemia:string! \
    persistent_vomiting:string! \
    palpable_abdominal_mass:string! \
    new_onset_symptoms_over_50:string! \
    family_history_gi_cancer:string! \
    family_gi_cancer_details:text! \
    night_sweats:string! \
    fever:string! \
    tobacco_use:string! \
    alcohol_use:string! \
    recreational_drug_use:string! \
    occupation:string! \
    travel_history:text! \
    stress_level:string! \
    psychological_impact:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    severity_score:int! \
    severity_level:string! \
    red_flag_count:int! \
    urgent_referral_recommended:bool! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
